### Problem Description

A `knn` query on a `semantic_text` field fails when it contains filters that are other queries on `semantic_text` fields (e.g. `knn`, `sparse_vector`, `match`).

### Steps to Reproduce

```
PUT example
{
    "settings": {
        "number_of_shards": 1,
        "number_of_replicas": 0
    },
    "mappings": {
        "properties": {
            "semantic_1": {
                "type": "semantic_text",
                "inference_id": ".multilingual-e5-small-elasticsearch"
            },
            "semantic_2": {
                "type": "semantic_text",
                "inference_id": ".multilingual-e5-small-elasticsearch"
            }
        }
    }
}

POST example/_doc
{
    "semantic_1" : "something",
    "semantic_2": "else"
}

POST example/_search
{

    "query": {
        "knn": {
            "field": "semantic_1",
            "k": 10,
            "num_candidates": 10,
            "query_vector_builder": {
                "text_embedding": {
                    "model_text":"something"
                }
            },
            "filter": {
                "match": {
                    "semantic_2": {
                        "query": "else"
                    }
                }
            }
        }
    }
}

POST example/_search
{

    "query": {
        "knn": {
            "field": "semantic_1",
            "k": 10,
            "num_candidates": 10,
            "query_vector_builder": {
                "text_embedding": {
                    "model_text":"something"
                }
            },
            "filter": {
                "knn": {
                    "field": "semantic_2",
                    "k": 10,
                    "num_candidates": 10,
                    "query_vector_builder": {
                        "text_embedding": {
                            "model_text":"else"
                        }
                    }
